import * as XLSX from 'xlsx'
import { removeTilde } from '../formatting/text.js'

/**
 * Exporta filas de una tabla TanStack a Excel
 */
export const exportTrxToExcel = (table) => {
  const currentRows = table.getRowModel().rows.map((row) => row.original)
  const worksheet = XLSX.utils.json_to_sheet(currentRows)
  const workbook = XLSX.utils.book_new()
  XLSX.utils.book_append_sheet(workbook, worksheet, 'Transacciones')
  XLSX.writeFile(workbook, 'transacciones_RDR.xlsx')
}

/**
 * Exporta el estado actual de una tabla TanStack como CSV
 */
export const exportTableCurrentState = (table, fileName) => {
  const visibleColumns = table.getVisibleLeafColumns()
  const rows = table.getRowModel().rows

  const headers = visibleColumns.map((col) => {
    const header = col.columnDef.header ?? col.id
    return removeTilde(header)
  })

  const csvRows = [
    headers.join(','),
    ...rows.map((row) => {
      return visibleColumns
        .map((col) => {
          const cellValue = row.getValue(col.id)
          if (cellValue instanceof Date) return `"${cellValue.toLocaleDateString('es-CL')}"`
          if (typeof cellValue === 'string') return `"${removeTilde(cellValue)}"`
          return cellValue
        })
        .join(',')
    }),
  ]

  const csvContent = csvRows.join('\n')
  const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' })
  const link = document.createElement('a')
  link.href = URL.createObjectURL(blob)
  link.setAttribute('download', `${fileName}.csv`)
  document.body.appendChild(link)
  link.click()
  document.body.removeChild(link)
}
